  ('hollow-body-hold', 'Add hollow rock prep only after 20s clean hold; avoid high rep rocks in Skill.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('arch-body-hold', 'Add slow arch rocks only if static hold is clean for 15s.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('hollow-to-arch-roll', 'Add directional cue (hollow → arch only) before full reversals.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('tuck-hold-rock', 'Controlled tuck rock 4–6 reps if shape stays closed.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('pike-fold-tall-sit', 'Add light reach hold at end range if hamstrings tolerate.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('straddle-sit-reach-lift', 'Alternate double-leg micro-lift if trunk stays stacked.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('front-support-shape-hold', 'Add scapular push at end of hold if wrists tolerate.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('rear-support-shape-hold', 'Add single-leg table only if wrists and shoulders tolerate.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('wall-body-line-drill', 'Add slow step-off walk maintaining line.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.'),
  ('stick-to-shape-freeze-game', 'Full shape deck with partner mirror check.', 'No sex-based default. Scale by trunk control, hip mobility, wrist tolerance, coordination, sport demand, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'adult_advanced'
);

