-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('hollow-body-hold', 'The hollow shape organizes anterior trunk tension, rib-pelvis stacking, and global body line — the same shape demanded in tumbling takeoffs, handstands, and bar work. Teaching it on the floor reduces compensation through the low back and neck before dynamic skill.', 'Belongs in Shape & Position Intelligence (hollow_shape) — first static shape athletes must own before hollow-to-arch transitions and inversion progressions.', 'Early in Shape & Position Intelligence after breathing and dead bug when athletes need a clean hollow before rolls, hand support, or tumbling.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not progress to hollow rocks if the static hold loses low-back contact or ribs flare.', 'Scale by lumbar control, neck tolerance, hip flexor length, and symptoms; regress to tuck hollow or feet on floor.'),
  ('arch-body-hold', 'Arch/superman shape builds awareness of posterior chain engagement and long-spine extension used in backward rolls, walkovers, and hollow-to-arch contrast. Modest lift teaches control without turning the drill into maximal back extension.', 'Belongs in Shape & Position Intelligence (arch_shape) — posterior counterpart to hollow before shape transitions and rolling foundations.', 'After hollow or breathing reset when athletes need extension awareness before backward rolls, bridges, or arch-to-hollow transitions.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not hyperextend or hold maximal arch isometrics here — that is Control / Resilience work.', 'Scale by extension tolerance, lumbar symptoms, and coordination; use unilateral lifts or shorter holds.'),
  ('hollow-to-arch-roll', 'Alternating hollow and arch through a slow roll teaches the athlete to maintain tension while changing body line — the same demand in rolling progressions and tumbling shape switches. Slow speed exposes breaks in line that fast rolls hide.', 'Belongs in Shape & Position Intelligence (shape_transition) — bridge between static shapes and rolling/tumbling foundations.', 'After clean hollow and arch holds when athletes need to feel shape change without momentum or fatigue.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not use high-rep roll circuits for conditioning; that belongs in Fitness. Do not assign without hollow and arch holds first.', 'Assist through hips, shorten range, or use egg roll before full hollow-to-arch.'),
  ('tuck-hold-rock', 'Tuck shape is the compression body line used in backward rolls, bar swings, and tuck jumps. Holding and lightly rocking the tuck builds spinal flexion control separate from hip flexor cramping.', 'Belongs in Shape & Position Intelligence (tuck_shape) — compression counterpart to long hollow/straddle lines.', 'After hollow awareness when athletes need compact shape control before backward rolls, tuck jumps, or bar tuck shapes.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not turn tuck rocks into high-rep abdominal conditioning.', 'Feet down between reps, smaller rock amplitude, or seated tuck hold.'),
  ('pike-fold-tall-sit', 'Pike shape combines hamstring length with spinal flexion control needed for jumps, casts, and floor pike skills. Alternating fold and tall sit teaches the athlete to find both compression and stacked posture.', 'Belongs in Shape & Position Intelligence (pike_shape) — compression line distinct from straddle and hollow.', 'When athletes need pike shape awareness before handstand pike entries, v-ups, or bar pike shapes — after breathing and core access.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not force maximal pike stretch or high-rep sit-ups disguised as pike folds.', 'Bent knees, elevated hips, or hands on floor beside hips for support.'),
  ('straddle-sit-reach-lift', 'Active straddle shape combines hip abduction control, adductor engagement, and trunk stack used in straddle jumps and press entries. Reach-and-lift teaches tension without passive oversplits.', 'Belongs in Shape & Position Intelligence (straddle_shape) — wide-base compression line before dynamic straddle skills.', 'After pike or hollow work when athletes need straddle line awareness before straddle jumps, press handstands, or beam straddle skills.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not force splits depth or high-rep leg lifts for conditioning in Skill.', 'Narrow straddle, bent knees, hand support behind, or single-leg lift only.'),
  ('front-support-shape-hold', 'Front support is the base shape for handstands, cartwheels, and bars. Teaching protraction, shoulder stack, and rib-pelvis control on the floor reduces sag and wrist collapse before inversion.', 'Belongs in Shape & Position Intelligence (support_shape) — anterior support line paired with rear support.', 'After wrist prep and dead bug when athletes need hand-support shape before cartwheel, handstand, or floor support skills.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not hold maximal plank time here; >30s or weighted planks → Control. Do not stack before fresh wrist prep.', 'Elevated hands, knees down, or shorter holds based on wrist and shoulder tolerance.'),
  ('rear-support-shape-hold', 'Rear support builds the posterior hand-support line used in bridges, table walks, and cast preparation. It complements front support so athletes feel both protraction and open-shoulder extension under load.', 'Belongs in Shape & Position Intelligence (support_shape) — posterior support counterpart to front support.', 'After front support when athletes need both support shapes before tumbling backward entries or cast prep.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not turn into high-rep hip thrusts or long table holds for conditioning.', 'Bent knees, elevated hands, or shorter holds; regress if wrist extension is limited.'),
  ('wall-body-line-drill', 'Wall line feedback gives immediate visual and tactile cues for global alignment used in handstands, sprint posture, and stuck landings. Overhead reach exposes rib flare that hollow work also targets.', 'Belongs in Shape & Position Intelligence (line_drill) — vertical line intelligence after floor shapes.', 'After static shapes when athletes need vertical line awareness before handstand line, wall sprint drill, or landing posture work.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. Do not use long wall sits or overhead holds >30s as conditioning.', 'Partial wall contact, arms at sides first, or single-arm reach.'),
  ('stick-to-shape-freeze-game', 'Random shape recall under cue links static shape learning to decision and timing — the same demand when a coach calls corrections mid-pass or when an athlete must rebuild line quickly between skills.', 'Belongs in Shape & Position Intelligence (shape_reaction) — perception-action capstone for the shape cluster, not a conditioning game.', 'Capstone of the shape cluster after static shapes 1–9 when athletes can hit shapes on verbal cue without conditioning fatigue.', 'Gymnastics shape programming rule: teach clean static shapes at low RPE in Skill first. Holds beyond ~30s or loaded isometrics belong in Control / Resilience; shape games that become conditioning belong in Fitness / Repeatability — not Skill. Do not rush dynamic transitions without prerequisite shapes in the same session. If athletes chase speed with sloppy shapes or elevated heart rate for multiple minutes, move the game to Fitness / Repeatability or reduce rounds.', 'Fewer shapes in rotation, longer rest, partner demo first, or stick to floor shapes only.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Optional shape-cluster validation education (see also skill_movement_intelligence_readiness in 104)
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'skill_shape_readiness',
  NULL,
  'Shape & Position Intelligence without pre-fatigue',
  'Static gymnastics shapes should sharpen body lines at low RPE — not become core burnouts, long isometrics, or conditioning games before Output.',
  'Shape cards teach hollow, arch, tuck, pike, straddle, support, line, and shape-recall patterns while athletes are fresh so tumbling and inversion skills inherit clean lines.',
  'Sloppy shapes under fatigue transfer into tumbling, hand support, and landing errors. The shape cluster belongs at low neural cost before dynamic skill or max output.',
  'Keep holds 10–20s at RPE 2–4, sequence Prepare breathing/dead bug/glute bridge before shapes, require prerequisite shapes before transitions and the freeze game, and move holds >30s or conditioning games to Control or Fitness.',
  'Do not assign long plank/hollow burnouts, split forcing, or AMRAP shape games in Skill — reduce dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
